    /// <summary>
    /// Configures HIPAA-compliant WCF binding with strong WS-Security settings.
    /// Uses AES-256 for symmetric encryption and RSA-OAEP with SHA-256 for key wrapping.
    /// Avoids weak algorithms (DES, 3DES, RC4, RSA v1.5 key transport, SHA-1 for signatures).
    /// </summary>
    public static class HipaaSecureBindingFactory
    {
        /// <summary>
        /// Creates a CustomBinding with message-level security using mutual X.509 certificates,
        /// AES-256-CBC encryption, and RSA-OAEP-SHA256 key wrap — all HIPAA-appropriate.
        /// </summary>
        public static CustomBinding CreateHipaaCompliantBinding()
        {
            // Use AsymmetricSecurityBindingElement for mutual certificate authentication
            var securityElement = (AsymmetricSecurityBindingElement)
                SecurityBindingElement.CreateMutualCertificateBindingElement(
                    MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10);

            // --- Strong algorithm suite: AES-256 for encryption, SHA-256 for digests/signatures ---
            // Basic256Sha256 uses:
            //   Symmetric encryption: AES-256-CBC
            //   Symmetric key wrap:   AES-256 Key Wrap
            //   Asymmetric key wrap:  RSA-OAEP (with SHA-1 MGF by default in WCF, but avoids RSA v1.5)
            //   Digest:               SHA-256
            //   Signature:            HMAC-SHA-256 (symmetric) / RSA-SHA-256 (asymmetric)
            //   Minimum symmetric key length: 256
            //   Minimum asymmetric key length: 1024 (we enforce 2048+ via certificate validation)
            securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

            // Require derived keys for additional protection
            securityElement.SetKeyDerivation(true);

            // Protect the entire message (sign then encrypt)
            securityElement.MessageProtectionOrder = MessageProtectionOrder.SignBeforeEncryptAndEncryptSignature;

            // Require signatures for all message parts
            securityElement.RequireSignatureConfirmation = true;

            // Include timestamp to prevent replay attacks
            securityElement.IncludeTimestamp = true;
            securityElement.LocalClientSettings.DetectReplays = true;
            securityElement.LocalClientSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
            securityElement.LocalClientSettings.ReplayWindow = TimeSpan.FromMinutes(5);
            securityElement.LocalClientSettings.TimestampValidityDuration = TimeSpan.FromMinutes(10);

            securityElement.LocalServiceSettings.DetectReplays = true;
            securityElement.LocalServiceSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
            securityElement.LocalServiceSettings.ReplayWindow = TimeSpan.FromMinutes(5);
            securityElement.LocalServiceSettings.TimestampValidityDuration = TimeSpan.FromMinutes(10);

            // Security header layout
            securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;

            // Build the custom binding with secure transport underneath
            var binding = new CustomBinding();
            binding.Elements.Add(securityElement);

            // Use MTOM encoding for efficient binary data (medical images, etc.)
            var textEncoding = new TextMessageEncodingBindingElement
            {
                MessageVersion = MessageVersion.Soap12WSAddressing10
            };
            binding.Elements.Add(textEncoding);

            // HTTPS transport for defense in depth (message security + transport security)
            var httpsTransport = new HttpsTransportBindingElement
            {
                RequireClientCertificate = true,
                MaxReceivedMessageSize = 67108864, // 64 MB for large medical records
                MaxBufferSize = 67108864,
                TransferMode = TransferMode.Buffered
            };
            binding.Elements.Add(httpsTransport);

            binding.SendTimeout = TimeSpan.FromMinutes(5);
            binding.ReceiveTimeout = TimeSpan.FromMinutes(10);
            binding.OpenTimeout = TimeSpan.FromMinutes(1);
            binding.CloseTimeout = TimeSpan.FromMinutes(1);

            return binding;
        }

        /// <summary>
        /// Alternative: WSHttpBinding with strong message security for simpler configuration.
        /// Still uses AES-256 and SHA-256 via Basic256Sha256 algorithm suite.
        /// </summary>
        public static WSHttpBinding CreateHipaaWsHttpBinding()
        {
            var binding = new WSHttpBinding(SecurityMode.TransportWithMessageCredential)
            {
                MaxReceivedMessageSize = 67108864,
                MaxBufferPoolSize = 67108864,
                ReaderQuotas =
                {
                    MaxDepth = 64,
                    MaxStringContentLength = 8388608,
                    MaxArrayLength = 16777216,
                    MaxBytesPerRead = 4096,
                    MaxNameTableCharCount = 16384
                },
                SendTimeout = TimeSpan.FromMinutes(5),
                ReceiveTimeout = TimeSpan.FromMinutes(10)
            };

            // Transport security (TLS 1.2+)
            binding.Security.Transport.ClientCredentialType = HttpClientCredentialType.Certificate;

            // Message security with mutual certificates and strong algorithms
            binding.Security.Message.ClientCredentialType = MessageCredentialType.Certificate;
            binding.Security.Message.NegotiateServiceCredential = false;
            binding.Security.Message.EstablishSecurityContext = true;
            binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

            return binding;
        }
    }

    /// <summary>
    /// Custom certificate validator that enforces HIPAA-appropriate key sizes
    /// and rejects certificates with weak signature algorithms.
    /// </summary>
    public class HipaaCertificateValidator : System.IdentityModel.Selectors.X509CertificateValidator
    {
        private const int MinimumRsaKeySize = 2048;

        public override void Validate(X509Certificate2 certificate)
        {
            if (certificate == null)
                throw new SecurityTokenValidationException("Certificate is null.");

            // Check expiration
            if (certificate.NotAfter < DateTime.UtcNow)
                throw new SecurityTokenValidationException("Certificate has expired.");

            if (certificate.NotBefore > DateTime.UtcNow)
                throw new SecurityTokenValidationException("Certificate is not yet valid.");

            // Enforce minimum RSA key size of 2048 bits
            if (certificate.PublicKey.Key is System.Security.Cryptography.RSA rsaKey)
            {
                if (rsaKey.KeySize < MinimumRsaKeySize)
                    throw new SecurityTokenValidationException(
                        $"Certificate RSA key size {rsaKey.KeySize} is below the minimum required {MinimumRsaKeySize} bits.");
            }

            // Reject certificates signed with weak algorithms
            string signatureAlgorithm = certificate.SignatureAlgorithm.FriendlyName?.ToUpperInvariant() ?? "";
            if (signatureAlgorithm.Contains("MD5") || signatureAlgorithm.Contains("MD2"))
                throw new SecurityTokenValidationException(
                    $"Certificate uses weak signature algorithm: {certificate.SignatureAlgorithm.FriendlyName}");

            if (signatureAlgorithm.Contains("SHA1") || signatureAlgorithm == "SHA1RSA")
                throw new SecurityTokenValidationException(
                    "Certificate uses SHA-1 signature algorithm which is deprecated. Use SHA-256 or stronger.");

            // Verify chain
            using (var chain = new X509Chain())
            {
                chain.ChainPolicy.RevocationMode = X509RevocationMode.Online;
                chain.ChainPolicy.RevocationFlag = X509RevocationFlag.EntireChain;
                chain.ChainPolicy.VerificationFlags = X509VerificationFlags.NoFlag;

                if (!chain.Build(certificate))
                {
                    string errors = "";
                    foreach (var status in chain.ChainStatus)
                    {
                        errors += $"{status.StatusInformation} ";
                    }
                    throw new SecurityTokenValidationException(
                        $"Certificate chain validation failed: {errors}");
                }
            }
        }
    }

