        public HealthcareServiceHostConfigurator(string baseAddress, string serviceCertThumbprint)
        {
            _baseAddress = baseAddress ?? throw new ArgumentNullException(nameof(baseAddress));
            _serviceCertThumbprint = serviceCertThumbprint ?? throw new ArgumentNullException(nameof(serviceCertThumbprint));
        }

        public ServiceHost ConfigureAndOpen()
        {
            _serviceHost = new ServiceHost(
                typeof(HealthcareRecordsServiceImpl),
                new Uri(_baseAddress));

            // Use the HIPAA-compliant custom binding
            CustomBinding secureBinding = HipaaSecureBindingFactory.CreateHipaaCompliantBinding();

            var endpoint = _serviceHost.AddServiceEndpoint(
                typeof(IHealthcareRecordsService),
                secureBinding,
                "HealthRecords");

            // Configure service certificate
            _serviceHost.Credentials.ServiceCertificate.SetCertificate(
                StoreLocation.LocalMachine,
                StoreName.My,
                X509FindType.FindByThumbprint,
                _serviceCertThumbprint);

            // Configure client certificate authentication with custom validator
            _serviceHost.Credentials.ClientCertificate.Authentication.CertificateValidationMode =
                System.ServiceModel.Security.X509CertificateValidationMode.Custom;
            _serviceHost.Credentials.ClientCertificate.Authentication.CustomCertificateValidator =
                new HipaaCertificateValidator();
            _serviceHost.Credentials.ClientCertificate.Authentication.RevocationMode =
                X509RevocationMode.Online;

            // Configure metadata (disable in production or restrict access)
            var metadataBehavior = _serviceHost.Description.Behaviors.Find<ServiceMetadataBehavior>();
            if (metadataBehavior == null)
            {
                metadataBehavior = new ServiceMetadataBehavior
                {
                    HttpsGetEnabled = true,
                    HttpGetEnabled = false // Only HTTPS for metadata
                };
                _serviceHost.Description.Behaviors.Add(metadataBehavior);
            }

            // Service debug behavior - disable detailed faults in production
            var debugBehavior = _serviceHost.Description.Behaviors.Find<ServiceDebugBehavior>();
            if (debugBehavior == null)
            {
                debugBehavior = new ServiceDebugBehavior { IncludeExceptionDetailInFaults = false };
                _serviceHost.Description.Behaviors.Add(debugBehavior);
            }
            else
            {
                debugBehavior.IncludeExceptionDetailInFaults = false;
            }

            // Throttling for production
            var throttleBehavior = _serviceHost.Description.Behaviors.Find<ServiceThrottlingBehavior>();
            if (throttleBehavior == null)
            {
                throttleBehavior = new ServiceThrottlingBehavior
                {
                    MaxConcurrentCalls = 100,
                    MaxConcurrentInstances = 100,
                    MaxConcurrentSessions = 100
                };
                _serviceHost.Description.Behaviors.Add(throttleBehavior);
            }

            _serviceHost.Open();
            return _serviceHost;
        }

        public void Close()
        {
            if (_serviceHost != null)
            {
                try
                {
                    if (_serviceHost.State == CommunicationState.Opened)
                        _serviceHost.Close();
                }
                catch
                {
                    _serviceHost.Abort();
                }
            }
        }
    }

