                EndpointIdentity.CreateX509CertificateIdentity(
                    FindCertificate(StoreLocation.LocalMachine, StoreName.TrustedPeople, serviceCertThumbprint)));

            var factory = new ChannelFactory<IHealthcareRecordsService>(binding, endpointAddr);

            // Set client certificate
            factory.Credentials.ClientCertificate.SetCertificate(
                StoreLocation.CurrentUser,
                StoreName.My,
                X509FindType.FindByThumbprint,
                clientCertThumbprint);

            // Set service certificate for message encryption
            factory.Credentials.ServiceCertificate.SetDefaultCertificate(
                StoreLocation.LocalMachine,
                StoreName.TrustedPeople,
                X509FindType.FindByThumbprint,
                serviceCertThumbprint);

            factory.Credentials.ServiceCertificate.Authentication.CertificateValidationMode =
                System.ServiceModel.Security.X509CertificateValidationMode.Custom;
            factory.Credentials.ServiceCertificate.Authentication.CustomCertificateValidator =
                new HipaaCertificateValidator();

            return factory;
        }

        private static X509Certificate2 FindCertificate(
            StoreLocation location, StoreName storeName, string thumbprint)
        {
            using (var store = new X509Store(storeName, location))
            {
                store.Open(OpenFlags.ReadOnly);
                var certs = store.Certificates.Find(
                    X509FindType.FindByThumbprint, thumbprint, validOnly: true);

                if (certs.Count == 0)
                    throw new InvalidOperationException(
                        $"Certificate with thumbprint '{thumbprint}' not found in {location}/{storeName}.");

                return certs[0];
            }
        }
    }

    /// <summary>
    /// Demonstrates the algorithm suite details and validates the security configuration.
    /// </summary>
    public static class SecurityConfigurationValidator
    {
        public static void ValidateAlgorithmSuite(SecurityAlgorithmSuite suite)
        {
            Console.WriteLine("=== HIPAA Security Algorithm Configuration ===");
            Console.WriteLine($"Algorithm Suite: {suite.GetType().Name}");
            Console.WriteLine($"Default Encryption Algorithm: {suite.DefaultEncryptionAlgorithm}");
            Console.WriteLine($"Default Symmetric Key Length: {suite.DefaultSymmetricKeyLength}");
            Console.WriteLine($"Default Asymmetric Key Wrap Algorithm: {suite.DefaultAsymmetricKeyWrapAlgorithm}");
            Console.WriteLine($"Default Symmetric Key Wrap Algorithm: {suite.DefaultSymmetricKeyWrapAlgorithm}");
            Console.WriteLine($"Default Digest Algorithm: {suite.DefaultDigestAlgorithm}");
            Console.WriteLine($"Default Asymmetric Signature Algorithm: {suite.DefaultAsymmetricSignatureAlgorithm}");
            Console.WriteLine($"Default Symmetric Signature Algorithm: {suite.DefaultSymmetricSignatureAlgorithm}");
            Console.WriteLine($"Default Canonicalization Algorithm: {suite.DefaultCanonicalizationAlgorithm}");

            // Validate no weak algorithms
            var weakAlgorithms = new[]
            {
                "http://www.w3.org/2001/04/xmlenc#tripledes-cbc",   // 3DES
                "http://www.w3.org/2001/04/xmlenc#des-cbc",          // DES
                "http://www.w3.org/2001/04/xmlenc#rsa-1_5",          // RSA v1.5 (padding oracle)
                "http://www.w3.org/2000/09/xmldsig#sha1",            // SHA-1 digest
                "http://www.w3.org/2000/09/xmldsig#hmac-sha1",       // HMAC-SHA1
                "http://www.w3.org/2000/09/xmldsig#rsa-sha1"         // RSA-SHA1
            };

            string[] currentAlgorithms = new[]
            {
                suite.DefaultEncryptionAlgorithm,
                suite.DefaultAsymmetricKeyWrapAlgorithm,
                suite.DefaultSymmetricKeyWrapAlgorithm,
                suite.DefaultDigestAlgorithm,
                suite.DefaultAsymmetricSignatureAlgorithm,
                suite.DefaultSymmetricSignatureAlgorithm
            };

            bool isSecure = true;
            foreach (var current in currentAlgorithms)
            {
                foreach (var weak in weakAlgorithms)
                {
                    if (string.Equals(current, weak, StringComparison.OrdinalIgnoreCase))
                    {
                        Console.WriteLine($"WARNING: Weak algorithm detected: {current}");
                        isSecure = false;
                    }
                }
            }

            if (suite.DefaultSymmetricKeyLength < 256)
            {
                Console.WriteLine($"WARNING: Symmetric key length {suite.DefaultSymmetricKeyLength} is below 256 bits.");
                isSecure = false;
            }

            Console.WriteLine($"\nSecurity Validation: {(isSecure ? "PASSED" : "FAILED")}");
            Console.WriteLine("================================================");
        }
    }

    // Program entry point
    class Program
    {
        static void Main(string[] args)
        {
            // Enforce TLS 1.2+ at the application level
            System.Net.ServicePointManager.SecurityProtocol =
                System.Net.SecurityProtocolType.Tls12 | System.Net.SecurityProtocolType.Tls13;

            Console.WriteLine("HIPAA-Compliant Healthcare Records SOAP Service");
            Console.WriteLine("================================================\n");

            // Validate the security configuration
            SecurityConfigurationValidator.ValidateAlgorithmSuite(SecurityAlgorithmSuite.Basic256Sha256);

            Console.WriteLine("\nBinding Configuration Details:");
            var binding = HipaaSecureBindingFactory.CreateHipaaCompliantBinding();
            Console.WriteLine($"Binding Name: {binding.Name}");
            Console.WriteLine($"Binding Elements:");
            foreach (var element in binding.Elements)
            {
                Console.WriteLine($"  - {element.GetType().Name}");
                if (element is AsymmetricSecurityBindingElement asymmetric)
                {
                    Console.WriteLine($"    Algorithm Suite: {asymmetric.DefaultAlgorithmSuite.GetType().Name}");
                    Console.WriteLine($"    Message Protection Order: {asymmetric.MessageProtectionOrder}");
                    Console.WriteLine($"    Require Signature Confirmation: {asymmetric.RequireSignatureConfirmation}");
                    Console.WriteLine($"    Include Timestamp: {asymmetric.IncludeTimestamp}");
                    Console.WriteLine($"    Replay Detection: {asymmetric.LocalServiceSettings.DetectReplays}");
                }
            }

            Console.WriteLine("\n--- Service Configuration Summary ---");
            Console.WriteLine("Encryption: AES-256-CBC (message level)");
            Console.WriteLine("Key Wrap: RSA-OAEP (asymmetric), AES-256 Key Wrap (symmetric)");
            Console.WriteLine("Digest: SHA-256");
            Console.WriteLine("Signature: RSA-SHA256 (asymmetric), HMAC-SHA256 (symmetric)");
            Console.WriteLine("Authentication: Mutual X.509 Certificates");
            Console.WriteLine("Transport: HTTPS (TLS 1.2+)");
            Console.WriteLine("Minimum RSA Key Size: 2048 bits");
            Console.WriteLine("Replay Protection: Enabled");
            Console.WriteLine("Timestamp Validation: Enabled");
            Console.WriteLine("HIPAA Audit Logging: Enabled");

            Console.WriteLine("\nTo start the service host, configure certificate thumbprints:");
            Console.WriteLine("  var configurator = new HealthcareServiceHostConfigurator(");
            Console.WriteLine("      \"https://localhost:8443/Healthcare\",");
            Console.WriteLine("      \"<service-cert-thumbprint>\");");
            Console.WriteLine("  var host = configurator.ConfigureAndOpen();");

            Console.WriteLine("\nPress any key to exit...");
            Console.ReadKey();
        }
    }
